/* ---- Accessibility: skip timeline animations for reduced-motion users ---- */

@media (prefers-reduced-motion: reduce) {
  .nacional-timeline__progress {
    animation: none;
    width: 100%;
  }

  .nacional-timeline__dot {
    opacity: 1;
    transform: scale(1);
    animation: none !important;
    background: var(--color-nacional);
    border-color: var(--color-nacional);
  }

  .nacional-timeline__label {
    opacity: 1;
    transform: translateX(-50%);
    animation: none !important;
  }

  /* --above labels — same final state for reduced-motion */
  .nacional-timeline__marker--above .nacional-timeline__label {
    transform: translateX(-50%);
  }
}

